#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int numVertices;
    int** adjLists;
} Graph;

// Function to create a graph
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = vertices;
    graph->adjLists = (int**) malloc(vertices * sizeof(int*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = (int*) malloc(2 * sizeof(int));
        graph->adjLists[i][0] = -1;
        graph->adjLists[i][1] = -1;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    int* newNode = (int*) malloc(2 * sizeof(int));
    newNode[0] = dest;
    newNode[1] = graph->adjLists[src][1];
    graph->adjLists[src][1] = newNode;
}

// Function to check if the graph is bipartite
int isBipartite(Graph* graph) {
    int* color = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        color[i] = -1;
    }
    for (int i = 0; i < graph->numVertices; i++) {
        if (color[i] == -1) {
            if (!dfs(graph, i, color, 1)) {
                return 0;
            }
        }
    }
    return 1;
}

// Function to perform DFS
int dfs(Graph* graph, int vertex, int* color, int col) {
    color[vertex] = col;
    int* adjList = graph->adjLists[vertex];
    while (adjList[1] != -1) {
        if (color[adjList[0]] == -1) {
            if (!dfs(graph, adjList[0], color, 1 - col)) {
                return 0;
            }
        } else if (color[adjList[0]] == col) {
            return 0;
        }
        adjList = adjList[1];
    }
    return 1;
}

int main() {
    int vertices;
    scanf("%d", &vertices);
    Graph* graph = createGraph(vertices);
    for (int i = 0; i < vertices; i++) {
        int numEdges;
        scanf("%d", &numEdges);
        for (int j = 0; j < numEdges; j++) {
            int dest;
            scanf("%d", &dest);
            addEdge(graph, i, dest);
        }
    }
    if (isBipartite(graph)) {
        printf("1\n");
    } else {
        printf("0\n");
    }
    return 0;
}

