from collections import defaultdict

class Solution:
    def isBipartite(self, V, adj):
        color = [-1] * V
        for i in range(V):
            if color[i] == -1:
                if not self.dfs(i, 0, color, adj):
                    return False
        return True

    def dfs(self, node, col, color, adj):
        color[node] = col
        for it in adj[node]:
            if color[it] == -1:
                if not self.dfs(it, 1 - col, color, adj):
                    return False
            elif color[it] == col:
                return False
        return True

